var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>챔버</color>","JPN":"管理局直轄都市<color=#ffd34c>チェンバー</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Chamber</color>","TWN":"管理局直轄市<color=#ffd34c>強巴</color>","SCN":"管理局直辖城市<color=#ffd34c>会议室</color>","DEU":"Administration Direct Control City, <color=#ffd34c>Chamber</color>","FRA":"Administration Direct Control City, <color=#ffd34c>Chamber</color>"},"stage":{"bg":"CHAMBER","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"시라사키 리프트 코퍼레이션\\n대균열 왕복 승강장 <color=#ffd34c>4-D</color>","JPN":"シラサキ・リフト・コーポレーション\\n大亀裂往復乗降場<color=#ffd34c>4-D</color>","ENG":"[[","TWN":"白崎起重所屬\\n大峽谷往返升降機 <color=#ffd34c>4-D</color>","SCN":"白崎起重所属\\n大裂谷往返升降机 <color=#ffd34c>4-D</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"승강기 배치 및 점검 완료되었습니다!","JPN":"昇降機の配置および点検、完了しました！","ENG":"The elevator's been inspected and placed!","TWN":"升降機部署及檢查完畢！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"다들 아시죠? 권장 체류 시간은 24시간이고요. 하강하겠습니다!","JPN":"皆さんご存じですよね？　滞在推奨時間は24時間です。では降ります！","ENG":"You all know, right? The recommended stay time is 24 hours. Descend!","TWN":"不用再說一遍了吧？建議停留時間是24小時。現在開始下降！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"승강기 하강!","JPN":"昇降機、下降！","ENG":"Elevator going down!","TWN":"升降機啟動！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"오오, 신기하네요.","JPN":"おお、不思議な感じですね。","ENG":"Whoa, this is incredible.","TWN":"喔喔，真神奇啊。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"차원함선을 쓰지 않고, 승강기를 이용한 다이브라니.","JPN":"次元艦船じゃなく昇降機を利用したダイブだなんて。","ENG":"A dive using an elevator instead of a dimensional ship.","TWN":"不使用次元戰艦，而是使用升降機進行躍入。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"하핫, 그라운드 원에서 왔다더니 초짜인가 보구만.","JPN":"ははっ、グラウンド・ワンから来たと聞いたが、初心者なんだな。","ENG":"Haha! I heard you were from Ground One, but guess you are a rookie, eh?","TWN":"哈哈，從G1來的吧？看來是個新手啊。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"여기 챔버 대균열은 다른 도시와 달리, 지하 깊은 곳에 위치하기 때문이야.","JPN":"ここチェンバーの大亀裂は他の都市とは違って、地下の深い場所にあるからだ。","ENG":"Chamber's Grand Dimension Crevice is unlike those of the other cities. It's located deep underground.","TWN":"強巴的大峽谷與其他城市不同，開在了地下深處。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이런 곳에는 거대한 차원 함선이 진입하기 쉽지 않거든.","JPN":"こういった場所では巨大な次元艦船だと出入りしづらいんでな。","ENG":"Also, it's hard for something as massive as a dimensional ship to enter a place like this.","TWN":"這種地方，巨大的次元艦船可不容易進來。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"프론트베이의 해저 대균열과 비슷하네요.","JPN":"フロントベイの海底大亀裂と似ていますね。","ENG":"It's similar to the one in Front Bay.","TWN":"和前灣的海底大峽谷很相似呢。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"그쪽도 특수한 차원 함선을 써야, 대균열로 다이브가 가능하다고 들었거든요.","JPN":"そこも特殊な次元艦船じゃないと大亀裂にダイブできないと聞きました。","ENG":"I heard that they also have to use a special dimensional ship to dive into the Grand Dimension Crevice.","TWN":"聽說他們也需要使用特殊的次元戰艦，才能潛入大峽谷。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"오, 듣고 보니 그렇구만.","JPN":"おお、そういえばそうだったな。","ENG":"Oh, come to think of it, you're right.","TWN":"喔，聽你這麼一說，確實是這樣。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"어쨌든 지하 대균열로 인해, 챔버의 이면세계 탐사는 독특한 방식으로 발전해왔어.","JPN":"とにかく地下の大亀裂の影響で、チェンバーの裏世界探査は独自の方法を発展させてきた。","ENG":"Anyway, due to the underground Grand Dimension Crevice, the Counterside expedition in Chamber has developed in a unique way.","TWN":"無論如何，由於地下大峽谷的存在，強巴的異界探索就以這種獨特的方式發展起來了。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 그 규모도 부대 단위의 태스크포스보다는 소규모 탐사대 위주지.","JPN":"だから、規模も部隊ごとのタスクフォースよりは、小規模の探査部隊が中心だ。","ENG":"That's why we tend to form exploration teams smaller than that of TASKFORCEs.","TWN":"所以規模上也更傾向於小型探險隊，而不是部隊級別的特遣隊。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐사가 많이 진행된 층 위주로 다니면 자네도 안전할 거야.","JPN":"探査が進んでいる階層を中心に移動すれば、君も安全だろうさ。","ENG":"You'll be safe as long as you stay on the floors that have already been explored a lot.","TWN":"如果你主要在已經探查過的層面活動，會比較安全。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 3층보다 아래로 내려가면 이야기가 달라지겠지만.","JPN":"もちろん、3階より下は話が違ってくるけどな。","ENG":"Of course, it's an entirely different case if you go below the 3rd floor.","TWN":"當然，如果你下到第三層以後，那情況就不一樣了。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"어어, 3층보다 아래로 내려가면 어떻게 되는데요?","JPN":"え、3階より下に行くと、どうなるんですか？","ENG":"Uh, what happens if I go below the 3rd floor?","TWN":"呃呃，到3層之後會怎麼樣？"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 표정을 보니 잔뜩 겁먹은 모양이군.","JPN":"ふふ、その顔は……怖気づいたな？","ENG":"Haha, don't get too scared already.","TWN":"呵呵，看你的表情，嚇壞了吧。"},"stage":{"bg":"GAME_LIFT","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"딱 한 번.","JPN":"一度だけ。","ENG":"Just once.","TWN":"有一次。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"승강기가 고장 나서 3층에 내려버린 적이 있었지.","JPN":"昇降機が故障して、3階に降りてしまったことがある。","ENG":"I got off on the 3rd floor because the elevator broke down.","TWN":"電梯壞了，我們被困在了三層。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이 승강기로 내려갈 수 있는 최저 지점이 3층이었거든.","JPN":"この昇降機で降りられる最低地点が3階だったんだ。","ENG":"You see, the lowest point this elevator can go is the 3rd floor.","TWN":"順便說一下，這部升降梯能到達的最深層就是三層。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐사대에 엔지니어가 있어서 승강기를 고쳐보려 했지만, 역부족이었어.","JPN":"探査部隊のエンジニアが何とか直せないかと手を尽くしてはみたが、無理だった。","ENG":"Our team had an engineer and we tried to fix the elevator, but we failed to do it.","TWN":"儘管探險隊裡有工程師試圖搶修，但還是不夠。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"어쩔 수 없이 우리는 지상으로 향하는 다른 승강기까지 어둠 속을 헤쳐 가야 했지.","JPN":"しかたなく俺たちは地上へ向かう他の昇降機まで、暗闇を進むしかなかった。","ENG":"We had no choice but to walk through the darkness to reach the other elevator that was going up.","TWN":"無奈之下，我們只能在黑暗中穿行，前往另一個通向地面的電梯。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};